/**
 * A Persistent Vector implementation using a Bitmapped Vector Trie.
 * This provides O(log32 N) time complexity for get and push operations,
 * ensuring structural sharing to avoid copying the entire array.
 */
export class PersistentVector<T> {
  private static readonly BITS = 5;
  private static readonly WIDTH = 1 << PersistentVector.BITS; // 32
  private static readonly MASK = PersistentVector.WIDTH - 1;

  private constructor(
    private readonly root: Node<T>,
    private readonly _size: number,
    private readonly shift: number
  ) {}

  static empty<T>(): PersistentVector<T> {
    return new PersistentVector<T>(new Node<T>(), 0, 0);
  }

  get size(): number {
    return this._size;
  }

  get(i: number): T {
    if (i < 0 || i >= this._size) {
      throw new Error("Index out of range");
    }

    let curr = this.root;
    for (let level = this.shift; level > 0; level -= PersistentVector.BITS) {
      curr = curr.children[(i >> level) & PersistentVector.MASK];
    }
    return curr.children[i & PersistentVector.MASK] as unknown as T;
  }

  push(value: T): PersistentVector<T> {
    // If the root is full, we need to increase the height of the tree
    if ((this._size >> this.shift) >= PersistentVector.WIDTH) {
      const newRoot = new Node<T>();
      newRoot.children[0] = this.root;
      newRoot.children[1] = this.createPath(this.shift, value);
      return new PersistentVector<T>(newRoot, this._size + 1, this.shift + PersistentVector.BITS);
    }

    return new PersistentVector<T>(
      this.pushRecursive(this.shift, this.root, value),
      this._size + 1,
      this.shift
    );
  }

  private pushRecursive(level: number, node: Node<T>, value: T): Node<T> {
    const newNode = node.clone();
    if (level === 0) {
      // We reached the leaf; find the first empty slot based on size
      // Note: The actual index is handled by the parent's pathing, 
      // but we need to know where in this specific leaf the value goes.
      // Since push is sequential, we can derive the index from size and shift.
      const idx = this._size & PersistentVector.MASK;
      newNode.children[idx] = value as unknown as Node<T>;
    } else {
      const subIdx = (this._size >> level) & PersistentVector.MASK;
      const child = node.children[subIdx];

      if (child === undefined) {
        // Create a new path of nodes down to the leaf
        newNode.children[subIdx] = this.createPath(level - PersistentVector.BITS, value);
      } else {
        // Recurse down and share the path
        newNode.children[subIdx] = this.pushRecursive(level - PersistentVector.BITS, child, value);
      }
    }
    return newNode;
  }

  private createPath(level: number, value: T): Node<T> {
    if (level === 0) {
      const leaf = new Node<T>();
      leaf.children[0] = value as unknown as Node<T>;
      return leaf;
    }
    const node = new Node<T>();
    node.children[0] = this.createPath(level - PersistentVector.BITS, value);
    return node;
  }
}

class Node<T> {
  // Using a fixed-size array for the trie nodes. 
  // We use 'unknown' to allow both child Nodes and leaf values of type T.
  children: unknown[] = new Array(PersistentVector.WIDTH);

  clone(): Node<T> {
    const newNode = new Node<T>();
    for (let i = 0; i < this.children.length; i++) {
      newNode.children[i] = this.children[i];
    }
    return newNode;
  }
}

export type Json = 
