  };

  const parseValue = (): Json => {
    skipWhitespace();
    if (pos >= s.length) throw new Error("Unexpected end of input");

    const char = s[pos];
    if (char === '{') return parseObject();
    if (char === '[') return parseArray();
    if (char === '"') return parseString();
    if (char === '-' || (char >= '0' && char <= '9')) return parseNumber();
    if (char === 't') return parseLiteral("true", true);
    if (char === 'f') return parseLiteral("false", false);
    if (char === 'n') return parseLiteral("null", null);

    throw new Error(`Unexpected character ${char} at position ${pos}`);
  };

  const parseString = (): string => {
    pos++; // skip opening quote
    let result = "";

    while (pos < s.length) {
      const char = s[pos++];
      if (char === '"') return result;
      if (char !== '\\') {
        result += char;
        continue;
      }

      if (pos >= s.length) throw new Error("Unterminated string escape");
      const esc = s[pos++];
      switch (esc) {
        case '"': result += '"'; break;
        case '\\': result += '\\'; break;
        case '/': result += '/'; break;
        case 'b': result += '\b'; break;
        case 'f': result += '\f'; break;
        case 'n': result += '\n'; break;
        case 'r': result += '\r'; break;
        case 't': result += '\t'; break;
        case 'u': {
          if (pos + 4 > s.length) throw new Error("Invalid unicode escape");
          const hex = s.substring(pos, pos + 4);
          pos += 4;
          if (!/^[0-9a-fA-F]{4}$/.test(hex)) throw new Error("Invalid hex in unicode escape");
          result += String.fromCharCode(parseInt(hex, 16));
          break;
        }
        default: throw new Error(`Invalid escape sequence \\${esc}`);
      }
    }
    throw new Error("Unterminated string");
  };

  const parseNumber = (): number => {
    let start = pos;
    if (s[pos] === '-') pos++;

    if (pos < s.length && s[pos] === '0') {
      pos++;
    } else if (pos < s.length && s[pos] >= '1' && s[pos] <= '9') {
      while (pos < s.length && s[pos] >= '0' && s[pos] <= '9') pos++;
    } else {
      throw new Error("Invalid number format");
    }

    if (pos < s.length && s[pos] === '.') {
      pos++;
      if (pos >= s.length || !(s[pos] >= '0' && s[pos] <= '9')) throw new Error("Invalid decimal");
      while (pos < s.length && s[pos] >= '0' && s[pos] <= '9') pos++;
    }

    if (pos < s.length && (s[pos] === 'e' || s[pos] === 'E')) {
      pos++;
      if (pos < s.length && (s[pos] === '+' || s[pos] === '-')) pos++;
      if (pos >= s.length || !(s[pos] >= '0' && s[pos] <= '9')) throw new Error("Invalid exponent");
      while (pos < s.length && s[pos] >= '0' && s[pos] <= '9') pos++;
    }

    const numStr = s.substring(start, pos);
    const num = Number(numStr);
    if (isNaN(num)) throw new Error("Invalid number");
    return num;
  };

  const parseLiteral = (literal: string, value: Json): Json => {
