export type ParseQuery<S extends string> = S extends "" 
  ? {} 
  : S extends `${infer Key}=${infer Value}&${infer Rest}` 
    ? { [K in Key]: Value } & ParseQuery<Rest> 
    : S extends `${infer Key}=${infer Value}` 
      ? { [K in Key]: Value } 
      : {};

export class EventEmitter<TEvents extends Record<string, unknown[]>> {
  private listeners: Map<keyof TEvents, Array<(...args: unknown[]) => void>> = new Map();

  on<K extends keyof TEvents>(name: K, handler: (...args: TEvents[K]) => void): void {
    const handlers = this.listeners.get(name) ?? [];
    handlers.push(handler);
    this.listeners.set(name, handlers);
  }

  emit<K extends keyof TEvents>(name: K, ...args: TEvents[K]): void {
    const handlers = this.listeners.get(name);
    if (handlers) {
      for (const handler of handlers) {
        // We cast to a function that accepts the specific event arguments 
        // to satisfy the call site while maintaining internal type safety.
        (handler as (...args: TEvents[K]) => void)(...args);
      }
    }
  }
}

export class MedianStream {
  private low = new Heap((a, b) => a > b); // Max-heap
  private high = new Heap((a, b) => a < b); // Min-heap

  add(n: number): void {
    if (this.low.size() === 0 || n <= this.low.peek()!) {
      this.low.push(n);
    } else {
      this.high.push(n);
    }

    // Balance heaps so size difference is at most 1
    if (this.low.size() > this.high.size() + 1) {
      this.high.push(this.low.pop()!);
    } else if (this.high.size() > this.low.size()) {
      this.low.push(this.high.pop()!);
    }
  }

  median(): number {
    const totalSize = this.low.size() + this.high.size();
    if (totalSize === 0) {
      throw new Error("No elements in stream");
    }

    if (this.low.size() > this.high.size()) {
      return this.low.peek()!;
    } else {
      return (this.low.peek()! + this.high.peek()!) / 2;
    }
  }
}

class Heap {
  private data: number[] = [];
  constructor(private compare: (a: number, b: number) => boolean) {}

  size(): number {
    return this.data.length;
  }

  peek(): number | undefined {
    return this.data[0];
  }

  push(val: number): void {
    this.data.push(val);
    this.bubbleUp(this.data.length - 1);
  }

  pop(): number | undefined {
    if (this.size() === 0) return undefined;
    const top = this.data[0];
    const bottom = this.data.pop()!;
    if (this.size() > 0) {
      this.data[0] = bottom;
      this.bubbleDown(0);
    }
    return top;
  }

  private bubbleUp(index: number): void {
    while (index > 0) {
      const parent = Math.floor((index - 1) / 2);
      if (this.compare(this.data[index], this.data[parent])) {
        this.swap(index, parent);
        index = parent;
      } else {
        break;
      }
    }
  }

  private bubbleDown(index: number): void {
    while (true) {
      let target = index;
      const left = 2 * index + 1;
      const right = 2 * index + 2;

      if (left < this.data.length && this.compare(this.data[left], this.data[target])) {
        target = left;
      }
      if (right < this.data.length && this.compare(this.data[right], this.data[target])) {
        target = right;
      }

      if (target !== index) {
        this.swap(index, target);
        index = target;
      } else {
        break;
      }
    }
  }

  private swap(i: number, j: number): void {
    const temp = this.data[i];
    this.data[i] = this.data[j];
    this.data[j] = temp;
  }
}
